using System;

class Program
{
    static void Main(string[] args)
    {
        for (int i = 1; i <= 5; i++)
        {
            if (i == 3)
            {
                continue; // 3-ü atlayır
            }
            if (i == 5)
            {
                break; // Dövrü dayandırır
            }
            Console.WriteLine($"Rəqəm: {i}");
        }
    }
}
// Output:
// Rəqəm: 1
// Rəqəm: 2
// Rəqəm: 4

